# inject_all_remaining.py  -- Batches EM through FZ  (dedupe-safe)
# Run with:  python inject_all_remaining.py
import pathlib, re, subprocess, sys

PY  = sys.executable
DIR = pathlib.Path(r'D:\projects\mapzimus-board')
DATA = DIR / 'data.js'

def mk(id,title,sub,typ,geo,fmt,sect,tbl,e,r,c,s,t,v,o,dr):
    raw=e*2+r*2+c*2+s*1.5+t*1+v*1.25+o*1
    vs=int((raw/10.75)*(1-0.3*(1-dr/100)))
    return ('{id:"'+id+'",title:"'+title+'",sub:"'+sub+'",type:"'+typ+'",'
            'geo:"'+geo+'",fmt:"'+fmt+'",section:"'+sect+'",tbl:"'+tbl+'",'
            'sc:{emotional:'+str(e)+',relatability:'+str(r)+',clarity:'+str(c)
            +',surprise:'+str(s)+',tension:'+str(t)+',visual:'+str(v)
            +',originality:'+str(o)+',data_ready:'+str(dr)+'}'
            ',vs:'+str(vs)+',topics:[],ext:[],status:"idea",notes:""}')

src = DATA.read_text(encoding='utf-8')
existing = set(re.findall(r'id:"([^"]+)"', src))
print(f'[inject] Loaded data.js  existing IDs: {len(existing)}')

I=[]

