if not new_ideas:
    print('[inject] Nothing to inject.')
else:
    # Strip the closing bracket
    text2 = src.rstrip()
    if text2.endswith(']; // end D'):
        text2 = text2[:-11].rstrip()
    elif text2.endswith('];'):
        text2 = text2[:-2].rstrip()

    tail = ',\n'.join(new_ideas)
    out = text2 + ',\n' + tail + '\n]; // end D\n'
    DATA.write_text(out, encoding='utf-8')
    print(f'[inject] Wrote {DATA}')

